+fn host_header_value(parsed: &ParsedUrl) -> String {
+    let host = if parsed.host.contains(':') && !parsed.host.starts_with('[') {
+        format!("[{}]", parsed.host)
+    } else {
+        parsed.host.clone()
+    };
+
+    let default_port = match parsed.scheme {
+        Scheme::Http => 80,
+        Scheme::Https => 443,
+    };
+
+    if parsed.port == default_port {
+        host
+    } else {
+        format!("{host}:{}", parsed.port)
+    }
+}
